//Generated by AI
const path = require("path");
const notesModel = require("../models/notes.model");
const { GoogleGenAI } = require("@google/genai");
const fs = require("fs");
const generatePlan = require("../utilis/shortNotes");

const ai = new GoogleGenAI({
    apiKey: process.env.GOOGLE_API_KEY
});



async function makeNotes(req, res) {
    try {

        const {
            subject,
            chapter,
            topicName,
            description
        } = req.body;

        const hasImage = !!req.file;
        const hasDescription =
            description &&
            description.trim() !== "";

        if (!hasImage && !hasDescription) {
            return res.status(400).json({
                message: "Please provide image or description"
            });
        }

        let extractedNotes = "";

        // CASE 1 : DESCRIPTION ONLY
        if (!hasImage && hasDescription) {

            extractedNotes = description;
        }

        // CASE 2 : IMAGE ONLY
        if (hasImage && !hasDescription) {

            const imagePath = path.join(
                process.cwd(),
                req.file.path
            );

            console.log("REQ FILE =>", req.file);
console.log("PATH =>", req.file.path);
console.log("EXISTS =>", fs.existsSync(req.file.path));

            const imageBuffer =
                fs.readFileSync(imagePath);

            const response =
                await ai.models.generateContent({
                    model: "gemini-2.5-flash",
                    contents: [
                        {
                            inlineData: {
                                mimeType: req.file.mimetype,
                                data: imageBuffer.toString("base64")
                            }
                        },
                        {
                            text:
                                "Extract all notes from this image. Keep all important content."
                        }
                    ]
                });

            extractedNotes =
                response.candidates[0]
                .content.parts[0].text;
        }

        // CASE 3 : IMAGE + DESCRIPTION
        if (hasImage && hasDescription) {

            const imagePath = path.join(
                process.cwd(),
                req.file.path
            );

            const imageBuffer =
                fs.readFileSync(imagePath);

            const response =
                await ai.models.generateContent({
                    model: "gemini-2.5-flash",
                    contents: [
                        {
                            inlineData: {
                                mimeType: req.file.mimetype,
                                data: imageBuffer.toString("base64")
                            }
                        },
                        {
                            text: `
Use BOTH the image and text.

Additional Notes:
${description}

Extract all important content.
`
                        }
                    ]
                });

            extractedNotes =
                response.candidates[0]
                .content.parts[0].text;
        }

        // GENERATE SHORT NOTES

        const aiNotes =
            await generatePlan({
                subject,
                chapter,
                notes: extractedNotes
            });

        let notes = await notesModel.findOne({
            user: req.user.id,
            subject
        });

        // SUBJECT DOES NOT EXIST

        if (!notes) {

            notes = await notesModel.create({
                user: req.user.id,
                subject,

                chapter: [
                    {
                        chapterName: chapter,

                        topics: [
                            {
                                topicName,

                                imageUrl:
                                    req.file?.path || "",

                                description:
                                    description || "",

                                aiNotes
                            }
                        ]
                    }
                ]
            });

            return res.status(201).json({
                message:
                    "Subject created successfully",
                notes
            });
        }

        const chapterData =
            notes.chapter.find(
                item =>
                    item.chapterName === chapter
            );

        // CHAPTER DOES NOT EXIST

        if (!chapterData) {

            notes.chapter.push({
                chapterName: chapter,

                topics: [
                    {
                        topicName,

                        imageUrl:
                            req.file?.path || "",

                        description:
                            description || "",

                        aiNotes
                    }
                ]
            });

            await notes.save();

            return res.status(201).json({
                message:
                    "Chapter created successfully",
                notes
            });
        }

        // CHAPTER EXISTS

        chapterData.topics.push({
            topicName,

            imageUrl:
                req.file?.path || "",

            description:
                description || "",

            aiNotes
        });

        await notes.save();

        return res.status(200).json({
            message:
                "Topic added successfully",
            notes
        });

    } catch (err) {

        console.log(err);

        return res.status(500).json({
            message: err.message
        });
    }
}

async function getSubjectList(req, res){
    try{
        const subjectList = await notesModel.find(
            {user: req.user.id},
            {
                subject: 1,
                createdAt:1
            }
        )
        return res.status(200).json({
            subjectList
        })

    }catch(err){
        return res.status(500).json({
            err
        })
    }
}

async function getChapterList(req, res){
    try{
        const { subjectId } = req.params;
        const chapterList = await notesModel.findOne({
            user: req.user.id,
            _id: subjectId
        },{
            subject: 1,
            chapter:1,
            createdAt:1
        })
        if(!chapterList){
            return res.status(404).json({
                message: "Chapter not found "
            })
        }
        const chapters = chapterList.chapter.map(chapter => ({
    _id: chapter._id,
    chapterName: chapter.chapterName
}));
        return res.status(200).json({
            subject: chapterList.subject,
            chapters,
            createdAt: chapterList.createdAt
        })

    }catch(err){
        return res.status(500).json({
            message: err.message
        })
    }
}

async function getTopicList(req, res){
    try{
        const { subjectId ,chapterId } = req.params;
        
        const notes = await notesModel.findOne({
            _id: subjectId,
            user: req.user.id,
        })
        if(!notes){
            return res.status(404).json({
                message: "Notes not found "
            })
        }

        const chapter = notes.chapter.find(
            item => item._id.toString()=== chapterId
        )
        if (!chapter) {
      return res.status(404).json({
        message: "Chapter not found"
      });
    }
    const topics = chapter.topics.map(topic => ({
        _id: topic._id,
        topicName : topic.topicName,
        createdAt: topic.createdAt
    }))

        return res.status(200).json({
            chapterName: chapter.chapterName,
            topics
        })


    }catch(err){
        return res.status(500).json({
            message: err.message
        })
    }
}

async function getTopicDescription(req, res) {
    try {
        const { subjectId, chapterId, topicId } = req.params;

        const notes = await notesModel.findOne({
            _id: subjectId,
            user: req.user.id
        });

        if (!notes) {
            return res.status(404).json({
                message: "Subject not found"
            });
        }

        const chapter = notes.chapter.find(
            item => item._id.toString() === chapterId
        );

        if (!chapter) {
            return res.status(404).json({
                message: "Chapter not found"
            });
        }

        const topic = chapter.topics.find(
            item => item._id.toString() === topicId
        );

        if (!topic) {
            return res.status(404).json({
                message: "Topic not found"
            });
        }

        return res.status(200).json({
            topic: {
                _id: topic._id,
                topicName: topic.topicName,
                description: topic.description,
                aiNotes: topic.aiNotes,
                imageUrl: topic.imageUrl,
                createdAt: topic.createdAt
            }
        });

    } catch (err) {
        return res.status(500).json({
            message: err.message
        });
    }
}


