//Update Topic Name
async function updateTopicName(req, res) {
    try {
        const { subjectId, chapterId, topicId } = req.params;
        const { topicName } = req.body;

        if (!topicName || topicName.trim() === "") {
            return res.status(400).json({
                message: "Topic name is required"
            });
        }

        const notes = await notesModel.findOne({
            _id: subjectId,
            user: req.user.id
        });

        if (!notes) {
            return res.status(404).json({
                message: "Subject not found"
            });
        }

        const chapter = notes.chapter.find(
            item => item._id.toString() === chapterId
        );

        if (!chapter) {
            return res.status(404).json({
                message: "Chapter not found"
            });
        }

        const topic = chapter.topics.find(
            item => item._id.toString() === topicId
        );

        if (!topic) {
            return res.status(404).json({
                message: "Topic not found"
            });
        }

        topic.topicName = topicName.trim();

        await notes.save();

        return res.status(200).json({
            message: "Topic updated successfully",
            topic
        });

    } catch (err) {
        return res.status(500).json({
            message: err.message
        });
    }
}

