//Delete Section 

//Delete Topic
async function deleteTopic(req, res) {
    try {
        const { subjectId, chapterId, topicId } = req.params;

        const notes = await notesModel.findOne({
            _id: subjectId,
            user: req.user.id
        });
        if (!notes) {
    return res.status(404).json({
        message: "Subject not found"
    });
}

        const chapter = notes.chapter.find(
            item => item._id.toString() === chapterId
        );

        if (!chapter) {
    return res.status(404).json({
        message: "Chapter not found"
    });
}

        const topicExists = chapter.topics.find(
            item => item._id.toString() === topicId
        );

        if (!topicExists) {
            return res.status(404).json({
                message: "Topic not found"
            });
        }

        // DELETE IMAGE FILE FIRST
       if (
    topicExists.imageUrl &&
    fs.existsSync(topicExists.imageUrl)
) {
    fs.unlinkSync(topicExists.imageUrl);
}

        // DELETE TOPIC FROM DATABASE
        chapter.topics.pull(topicId);

        await notes.save();

        return res.status(200).json({
            message: "Topic deleted successfully"
        });

    } catch (err) {
        return res.status(500).json({
            message: err.message
        });
    }
}

//Delete Chapter
async function deleteChapter(req, res) {
    try {
        const { subjectId, chapterId } = req.params;

        const notes = await notesModel.findOne({
            _id: subjectId,
            user: req.user.id
        });

        if (!notes) {
            return res.status(404).json({
                message: "Subject not found"
            });
        }

        const chapterExists = notes.chapter.find(
            item => item._id.toString() === chapterId
        );

        if (!chapterExists) {
            return res.status(404).json({
                message: "Chapter not found"
            });
        }

        notes.chapter.pull(chapterId);

        await notes.save();

        return res.status(200).json({
            message: "Chapter deleted successfully"
        });

    } catch (err) {
        return res.status(500).json({
            message: err.message
        });
    }
}

//Delete Subject
async function deleteSubject(req, res) {
    try {
        const { subjectId } = req.params;

        const notes = await notesModel.findOneAndDelete({
            _id: subjectId,
            user: req.user.id
        });

        if (!notes) {
            return res.status(404).json({
                message: "Subject not found"
            });
        }

        return res.status(200).json({
            message: "Subject deleted successfully"
        });

    } catch (err) {
        return res.status(500).json({
            message: err.message
        });
    }
}

